def sanitize_log_message(message):
    """Remove or replace characters that could be used for log injection."""
    if not isinstance(message, str):
        return ""
    # Replace control characters (newlines, carriage returns, null bytes, etc.)
    sanitized = LOG_INJECTION_PATTERN.sub("\\\\n", message)
    # Truncate to maximum allowed length
    if len(sanitized) > MAX_MESSAGE_LENGTH:
        sanitized = sanitized[:MAX_MESSAGE_LENGTH] + "...[TRUNCATED]"
    return sanitized


def sanitize_field(value, max_length=256):
    """Sanitize a generic field value."""
    if not isinstance(value, str):
        return ""
    sanitized = LOG_INJECTION_PATTERN.sub("", value)
    return sanitized[:max_length]


def validate_service_name(service_name):
    """Validate service name against allowlist and pattern."""
    if not isinstance(service_name, str):
        return False
    if not SERVICE_NAME_PATTERN.match(service_name):
        return False
    if service_name not in ALLOWED_SERVICES:
        return False
    return True


def validate_log_level(level):
    """Validate log level against allowlist."""
    if not isinstance(level, str):
        return False
    return level.upper() in ALLOWED_LOG_LEVELS


def verify_hmac_signature(body_bytes, provided_signature):
    """Verify HMAC-SHA256 signature of the request body."""
    if not SHARED_SECRET:
        # If no secret is configured, reject all requests in production
        # For development, you might want to log a warning
        return False
    expected = hmac.new(
        SHARED_SECRET.encode("utf-8"),
        body_bytes,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected, provided_signature)


