# Rate limiting per service (simple in-memory)
class RateLimiter:
    def __init__(self, max_requests_per_second=100):
        self.max_rps = max_requests_per_second
        self.request_counts = {}
        self.window_start = {}

    def is_allowed(self, service_name):
        now = time.monotonic()
        window = int(now)

        if service_name not in self.window_start or self.window_start[service_name] != window:
            self.window_start[service_name] = window
            self.request_counts[service_name] = 0

        self.request_counts[service_name] += 1
        return self.request_counts[service_name] <= self.max_rps


rate_limiter = RateLimiter(max_requests_per_second=100)


class LogRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for receiving log messages from microservices."""

    # Suppress default logging to stderr to avoid information leakage
    def log_message(self, format, *args):
        pass

    def do_POST(self):
        """Handle POST requests to submit log entries."""
        # Only accept requests to /log endpoint
        parsed_path = urlparse(self.path)
        if parsed_path.path != "/log":
            self.send_error_response(404, "Not Found")
            return

        # Check Content-Length to prevent oversized requests
        content_length = self.headers.get("Content-Length")
        if content_length is None:
            self.send_error_response(411, "Length Required")
            return

        try:
            content_length = int(content_length)
        except (ValueError, TypeError):
            self.send_error_response(400, "Invalid Content-Length")
            return

        if content_length > MAX_REQUEST_BODY:
            self.send_error_response(413, "Request Too Large")
            return

        if content_length < 0:
            self.send_error_response(400, "Invalid Content-Length")
            return

        # Check Content-Type
        content_type = self.headers.get("Content-Type", "")
        if "application/json" not in content_type:
            self.send_error_response(415, "Unsupported Media Type")
            return

        # Verify HMAC authentication
        provided_signature = self.headers.get("X-Log-Signature", "")
        if not provided_signature:
            client_addr = sanitize_field(str(self.client_address[0]))
            security_logger.warning(
                "Missing HMAC signature from client %s", client_addr
            )
            self.send_error_response(401, "Unauthorized")
            return

        # Read request body
        try:
            body_bytes = self.rfile.read(content_length)
        except Exception:
            self.send_error_response(400, "Failed to read request body")
            return

        # Verify signature
        if not verify_hmac_signature(body_bytes, provided_signature):
            client_addr = sanitize_field(str(self.client_address[0]))
            security_logger.warning(
                "Invalid HMAC signature from client %s", client_addr
            )
            self.send_error_response(403, "Forbidden")
            return

        # Parse JSON body
        try:
            data = json.loads(body_bytes.decode("utf-8"))
        except (json.JSONDecodeError, UnicodeDecodeError):
            self.send_error_response(400, "Invalid JSON")
            return

        if not isinstance(data, dict):
            self.send_error_response(400, "Expected JSON object")
            return

        # Extract and validate fields
        service_name = data.get("service", "")
        log_level = data.get("level", "")
        message = data.get("message", "")
        request_id = data.get("request_id", "")
        timestamp = data.get("timestamp", "")

        # Validate service name
        if not validate_service_name(service_name):
            client_addr = sanitize_field(str(self.client_address[0]))
            security_logger.warning(
                "Invalid or unauthorized service name from client %s: %s",
                client_addr,
                sanitize_field(str(service_name)[:64])
            )
            self.send_error_response(403, "Service not authorized")
            return

