def create_log_client_helper():
    """
    Helper function that microservices can use to send logs.
    Returns a function that sends authenticated log messages.
    """
    import urllib.request

    def send_log(service_name, level, message, request_id="", server_url=None):
        if server_url is None:
            server_url = "http://{}:{}/log".format(LISTEN_HOST, LISTEN_PORT)

        payload = json.dumps({
            "service": service_name,
            "level": level,
            "message": message,
            "request_id": request_id,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }).encode("utf-8")

        # Compute HMAC signature
        signature = hmac.new(
            SHARED_SECRET.encode("utf-8"),
            payload,
            hashlib.sha256
        ).hexdigest()

        req = urllib.request.Request(
            server_url,
            data=payload,
            headers={
                "Content-Type": "application/json",
                "X-Log-Signature": signature,
            },
            method="POST"
        )

        try:
            with urllib.request.urlopen(req, timeout=5) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except Exception as e:
            # Fallback: print to stderr if logging server is unavailable
            print("Failed to send log: {}".format(e), flush=True)
            return None

    return send_log


